                    pq.enqueue([v, newCost, true]);
                }
            }
        }

        // Try not using the switch at this node
        for (const [v, w] of graph.get(node) || []) {
            const newCost = cost + w;
            if (dist[v] === -1 || newCost < dist[v]) {
                dist[v] = newCost;
                pq.enqueue([v, newCost, false]);
            }
        }
    }

    return -1;
}

