import { PriorityQueue } from 'typescript-collections';

function solve(n, edges) {
    const graph = new Map();
    for (const [u, v, w] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push({ to: v, weight: w });
    }

    const dist = new Array(n).fill(-1);
    dist[0] = 0;

    const pq = new PriorityQueue((a, b) => a[1] - b[1]);
    pq.enqueue([0, 0, false]); // [node, cost, hasSwitchUsed]

    while (!pq.isEmpty()) {
        const [node, cost, hasSwitchUsed] = pq.dequeue();
        if (node === n - 1) {
            return cost;
        }
        if (dist[node] !== -1 && dist[node] < cost) {
            continue;
        }

        if (!hasSwitchUsed) {
            // Try using the switch at this node
            for (const [v, w] of graph.get(node) || []) {
                const newCost = cost + 2 * w;
                if (dist[v] === -1 || newCost < dist[v]) {
                    dist[v] = newCost;
                    pq.enqueue([v, newCost, true]);
                }
            }
        }

        // Try not using the switch at this node
        for (const [v, w] of graph.get(node) || []) {
            const newCost = cost + w;
            if (dist[v] === -1 || newCost < dist[v]) {
                dist[v] = newCost;
                pq.enqueue([v, newCost, false]);
            }
        }
    }

    return -1;
}

